import{_ as r,o as e,c as a,a2 as d}from"./chunks/framework.c3r8iWL8.js";const p=JSON.parse('{"title":"Guide: Dashboards & Reporting","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/dashboards-reporting.md","filePath":"guides/dashboards-reporting.md","lastUpdated":1782929962000}'),o={name:"guides/dashboards-reporting.md"};function n(i,t,s,l,g,h){return e(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="guide-dashboards-reporting" tabindex="-1">Guide: Dashboards &amp; Reporting <a class="header-anchor" href="#guide-dashboards-reporting" aria-label="Permalink to &quot;Guide: Dashboards &amp; Reporting&quot;">​</a></h1><p><strong>Decision:</strong> What to visualize for on-call, engineering, product, and leadership — and how reporting connects to SLOs and incidents.</p><p>Related: <a href="./monitoring-tracing-logging.html">monitoring-tracing-logging.md</a> · <a href="./incident-management.html">incident-management.md</a> · <a href="./observability-monitoring-qa.html">observability-monitoring-qa.md</a></p><hr><h2 id="audience-layers" tabindex="-1">Audience layers <a class="header-anchor" href="#audience-layers" aria-label="Permalink to &quot;Audience layers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Audience</th><th>Needs</th><th>Refresh</th><th>Tooling bias</th></tr></thead><tbody><tr><td><strong>On-call / SRE</strong></td><td>Golden signals, recent deploys, open incidents</td><td>Real-time</td><td>CloudWatch, Grafana, Datadog</td></tr><tr><td><strong>Service team</strong></td><td>SLO budget, error breakdown, trace links</td><td>Daily</td><td>Same + custom boards</td></tr><tr><td><strong>Product / PO</strong></td><td>Business KPIs, feature flag exposure</td><td>Daily/weekly</td><td>RUM, custom metrics, BI</td></tr><tr><td><strong>Leadership</strong></td><td>Reliability summary, incident trends, cost</td><td>Weekly/monthly</td><td>Reporting exports, PDF/email</td></tr><tr><td><strong>Compliance / audit</strong></td><td>Access logs, data processing evidence</td><td>Monthly</td><td>CloudTrail, catalog reports</td></tr></tbody></table><p><strong>Pitfall:</strong> One dashboard for everyone → useless for all. Separate <strong>operational</strong> vs <strong>executive</strong> views.</p><hr><h2 id="dashboard-platforms" tabindex="-1">Dashboard platforms <a class="header-anchor" href="#dashboard-platforms" aria-label="Permalink to &quot;Dashboard platforms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Platform</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>CloudWatch Dashboards</strong></td><td>Native; alarm integration</td><td>Limited UX; cross-account hard</td></tr><tr><td><strong>Amazon Managed Grafana (AMG)</strong></td><td>PromQL + CW data sources</td><td>Setup + SSO</td></tr><tr><td><strong>Datadog / New Relic</strong></td><td>Best UX; unified APM</td><td>Cost at scale</td></tr><tr><td><strong>Grafana Cloud</strong></td><td>Managed Grafana</td><td>Data egress costs</td></tr><tr><td><strong>QuickSight</strong></td><td>Exec BI, SQL sources</td><td>Not for second-level on-call</td></tr></tbody></table><p><strong>Recommended:</strong> CloudWatch or AMG for ops; QuickSight or Grafana for exec/business when needed.</p><hr><h2 id="golden-dashboard-per-t1-service" tabindex="-1">Golden dashboard (per T1 service) <a class="header-anchor" href="#golden-dashboard-per-t1-service" aria-label="Permalink to &quot;Golden dashboard (per T1 service)&quot;">​</a></h2><p>Minimum panels:</p><ol><li><strong>Traffic</strong> — requests/sec</li><li><strong>Errors</strong> — rate + top error classes</li><li><strong>Latency</strong> — p50 / p95 / p99</li><li><strong>Saturation</strong> — CPU, queue depth, DB connections</li><li><strong>SLO</strong> — error budget remaining (28d window)</li><li><strong>Deploy markers</strong> — version annotations</li><li><strong>Open alerts</strong> — link to incident ticket</li><li><strong>Synthetic status</strong> — last canary run</li></ol><p>Template in <strong>your</strong> repo; this guide defines content only.</p><hr><h2 id="slo-reporting" tabindex="-1">SLO reporting <a class="header-anchor" href="#slo-reporting" aria-label="Permalink to &quot;SLO reporting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>Definition</th></tr></thead><tbody><tr><td><strong>SLI</strong></td><td>Measurable indicator (e.g. successful requests / total)</td></tr><tr><td><strong>SLO</strong></td><td>Target (e.g. 99.9% over 30d)</td></tr><tr><td><strong>Error budget</strong></td><td>Allowed unreliability before freeze</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Reporting artifact</th><th>Audience</th><th>Frequency</th></tr></thead><tbody><tr><td><strong>Error budget burn chart</strong></td><td>Eng + SRE</td><td>Daily in standup</td></tr><tr><td><strong>SLO compliance report</strong></td><td>Leadership</td><td>Monthly</td></tr><tr><td><strong>Missed SLO postmortem list</strong></td><td>ARCH + EM</td><td>Quarterly review</td></tr></tbody></table><p>Tools: Sloth + Prometheus, Datadog SLOs, AWS Application Signals (evolving), custom CW metrics.</p><hr><h2 id="business-product-reporting" tabindex="-1">Business &amp; product reporting <a class="header-anchor" href="#business-product-reporting" aria-label="Permalink to &quot;Business &amp; product reporting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Metrics</th><th>Pitfall</th></tr></thead><tbody><tr><td><strong>Application custom metrics</strong></td><td>Conversion, cart abandon</td><td>Not wired in AI-generated code</td></tr><tr><td><strong>RUM</strong></td><td>Web vitals, JS errors</td><td>Privacy consent</td></tr><tr><td><strong>Warehouse (Redshift, Snowflake)</strong></td><td>Batch KPIs</td><td>Stale vs real-time ops</td></tr><tr><td><strong>Event streams (Kinesis → analytics)</strong></td><td>Near-real-time</td><td>Schema governance</td></tr></tbody></table><p>AI planning agents can <strong>draft</strong> KPI definitions; PO must approve and link to spec.</p><hr><h2 id="incident-reliability-reporting" tabindex="-1">Incident &amp; reliability reporting <a class="header-anchor" href="#incident-reliability-reporting" aria-label="Permalink to &quot;Incident &amp; reliability reporting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Report</th><th>Contents</th><th>Owner</th></tr></thead><tbody><tr><td><strong>Weekly ops review</strong></td><td>Incidents, MTTR, top alerts</td><td>SRE</td></tr><tr><td><strong>Monthly reliability</strong></td><td>SLO attainment, repeat incidents</td><td>EM</td></tr><tr><td><strong>Quarterly architecture</strong></td><td>Trends driving ADR updates</td><td>ARCH</td></tr></tbody></table><p>Auto-generate draft narrative from incident DB + metrics (AI); human edits before exec send.</p><hr><h2 id="audit-data-governance-reporting" tabindex="-1">Audit &amp; data governance reporting <a class="header-anchor" href="#audit-data-governance-reporting" aria-label="Permalink to &quot;Audit &amp; data governance reporting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Report</th><th>Source</th></tr></thead><tbody><tr><td>Who accessed dataset X</td><td>Lake Formation audit, CloudTrail</td></tr><tr><td>PII scan findings</td><td>Macie</td></tr><tr><td>AI model invocations</td><td>Bedrock logging</td></tr><tr><td>Retention compliance</td><td>S3 lifecycle + legal hold status</td></tr></tbody></table><p>See <a href="./data-governance.html">data-governance.md</a>.</p><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>Dashboard sprawl</strong></td><td>Nobody knows canonical view</td><td>One golden dashboard per service</td></tr><tr><td><strong>Vanity metrics</strong></td><td>Green dashboard, angry customers</td><td>Pair with synthetics + RUM</td></tr><tr><td><strong>No deploy markers</strong></td><td>Can&#39;t correlate releases</td><td>CI writes version to metrics</td></tr><tr><td><strong>SLO without alert</strong></td><td>Report-only reliability</td><td>Burn-rate alerts</td></tr><tr><td><strong>Exec dashboard too granular</strong></td><td>Noise</td><td>Roll up to SLO + incident count</td></tr><tr><td><strong>Manual monthly reports</strong></td><td>Drift; wasted time</td><td>Scheduled Grafana/QuickSight</td></tr><tr><td><strong>PII in shared dashboards</strong></td><td>Access control failure</td><td>Aggregate; no customer IDs in widgets</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><p>Golden dashboard per T1 service in CloudWatch or AMG → SLO error budget panel → weekly automated ops email → monthly exec summary from same data source → incident count + MTTR trend.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./monitoring-tracing-logging.html">Monitoring, tracing &amp; logging</a> · <a href="./incident-management.html">Incident management</a> · <a href="./observability-monitoring-qa.html">Observability as QA</a></li></ul>',42)])])}const u=r(o,[["render",n]]);export{p as __pageData,u as default};
